const item = $json;

// Solo bloqueamos si es TRASH absoluto o si ya fue rechazado por Guard
if (item.category === 'trash' || item.trash === true) return [];

let score = 0;
// Scoring dinámico para el feed
if (item.category === 'evento') score += 50;
if (item.category === 'plaza') score += 20;
if (item.city && item.city !== 'Global') score += 15;
if ((item.text_es || '').length > 200) score += 10;

return [{ json: { ...item, final_score: score } }];

const item = $input.first()?.json || {};
function escapeHTML(text) { return String(text||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

const langs = [
  { code: 'ES', tg: '-5283488138', wa: '120363425790792660@g.us', title: item.title_es || 'Nuevo Lead', text: item.text_es || item.texto_limpio, tag: 'Remitente' },
  { code: 'EN', tg: '-1003757267210', wa: '120363408216646972@g.us', title: item.title_en || item.title_es || 'New Lead', text: item.text_en || item.text_es || item.texto_limpio, tag: 'Sender' },
  { code: 'RU', tg: '-1003920309636', wa: '120363408298375271@g.us', title: item.title_ru || item.title_es || 'Новый Лид', text: item.text_ru || item.text_es || item.texto_limpio, tag: 'Отправитель' },
  { code: 'PT', tg: '-1003727383883', wa: '120363426262586004@g.us', title: item.title_pt || item.title_es || 'Novo Lead', text: item.text_pt || item.text_es || item.texto_limpio, tag: 'Remetente' }
];

// --- INJECTED: COSTA AZUL CLIENT (PORTUGUESE) ---
function normalize(str) { return str.normalize("NFD").replace(/[̀-ͯ]/g, ""); }
const cityRaw = normalize(String(item.city || 'Global').toLowerCase());
const textRaw = normalize(String(item.text_es || '').toLowerCase());
const monacoRegex = /\b(monaco|cannes|niza|nice|monte carlo|côte d'azur)\b/i;
if (monacoRegex.test(cityRaw) || monacoRegex.test(textRaw)) {
  // Envía a la clienta (Telegram)
  langs.push({ code: 'PT_CLIENT', tg: '5479166354', wa: '5511953600828@s.whatsapp.net', title: item.title_pt || item.title_es || 'Novo Lead', text: item.text_pt || item.text_es || item.texto_limpio, tag: 'Remetente' });
  // Envía a la clienta 2 (Telegram y WhatsApp)
  langs.push({ code: 'PT_CLIENT_2', tg: '8799609531', wa: '33672474796@s.whatsapp.net', title: item.title_pt || item.title_es || 'Novo Lead', text: item.text_pt || item.text_es || item.texto_limpio, tag: 'Remetente' });
  // Envía al grupo de referencias
    // Cliente 3 (Nuevo Telegram)
  langs.push({ code: 'PT_CLIENT_3', tg: '8653719069', title: item.title_pt || item.title_es || 'Novo Lead', text: item.text_pt || item.text_es || item.texto_limpio, tag: 'Remetente' });
  langs.push({ code: 'PT_GROUP', tg: '-1003918368381', title: item.title_pt || item.title_es || 'Novo Lead', text: item.text_pt || item.text_es || item.texto_limpio, tag: 'Remetente' });
}
// -----------------------------------

const results = [];
for (const l of langs) {
  function formatOutputContact(val, mode) {
    if (!val || val === 'Desconocido' || val === 'No disponible') return 'No disponible';
    if (String(val).startsWith('tg_id_')) {
      const id = val.replace('tg_id_', '');
      return mode === 'html' ? `<a href="tg://user?id=${id}">Chat Directo</a>` : `ID: ${id}`;
    }
    if (/[a-zA-Z]/.test(val) && !/\d/.test(val)) {
       const user = String(val).replace('@', '');
       return mode === 'html' ? `<a href="https://t.me/${user}">@${user}</a>` : `@${user}`;
    }
    const s = String(val).replace(/[^0-9]/g, '');
    return s.length >= 7 ? `+${s}` : val;
  }

  const tgContact = formatOutputContact(item.contact || item.final_contact, 'html');
  const waContact = formatOutputContact(item.contact || item.final_contact, 'text');

  const isPt = l.code.startsWith('PT');
  const categoryStr = (item.category === 'plaza') ? (isPt ? 'Vagas' : 'Plazas') : 'Eventos';
  const unkCity = isPt ? 'Desconhecida' : 'Desconocida';
  const unkBudget = isPt ? 'Negociável' : 'Negociable';
  const noText = isPt ? 'Sem descrição' : 'Sin texto';
  const sourceLabel = isPt ? 'Fonte' : 'Fuente';

  let finalTgContact = tgContact;
  let finalWaContact = waContact;

  if (l.isPublic) {
    finalTgContact = `<a href="https://t.me/TuCuentaVIP">🔐 Скрыт (Доступно в VIP)</a>`;
    finalWaContact = `🔐 Скрыт (Доступно в VIP)`;
  }

  const tgText = `<b>${escapeHTML(l.title)}</b>\n📍 <b>${categoryStr}</b>\n🏢 <b>${escapeHTML(item.city || unkCity)}</b>\n💰 <b>${escapeHTML(item.budget || unkBudget)}</b>\n\n${escapeHTML(l.text || noText)}\n\n📲 <b>${l.tag}:</b> ${finalTgContact}\n🌐 <b>${sourceLabel}:</b> ${escapeHTML(item.platform || 'WhatsApp')}`;
  const waText = `*🌟 ${l.title}*\n📍 *${item.city || unkCity}* | 💰 *${item.budget || unkBudget}*\n\n${l.text || noText}\n\n📲 *${l.tag}:* ${finalWaContact}\n🌐 *${sourceLabel}:* ${item.platform || 'WhatsApp'}`;

  results.push({
    json: { ...item, route_lang: l.code, tg_chat: l.tg, tg_text: tgText, wa_chat: l.wa, wa_text: waText }
  });
}
return results;

// DYNAMIC ROUTING ENGINE v7.1 (CLEAN CLIENTS ONLY)
let leadData = $input.first().json;
const category = String(leadData.category || 'evento').toLowerCase();
const cityDetected = String(leadData.city || 'global').toLowerCase();
const text = String(leadData.text_es || '').toLowerCase();

// NORMALIZAMOS EL TEXTO PARA EVITAR PROBLEMAS CON TILDES
function normalize(str) {
  return str.normalize("NFD").replace(/[\u0300-\u036f]/g, "");
}
const textNorm = normalize(text);
const cityNorm = normalize(cityDetected);

const routingTable = {
  "costa_azul": {
    keywords: ["monaco", "cannes", "niza", "nice", "monte carlo", "cote d'azur"],
    targets: [
      { to: "5511953600828@s.whatsapp.net", label: "COSTA AZUL" },
      { to: "447471373828@s.whatsapp.net", label: "COSTA AZUL" }
    ]
  }
};

let matchedTargets = [];

for (const [key, config] of Object.entries(routingTable)) {
    // Usamos expresión regular con fronteras de palabra (\b) para evitar coincidencias parciales
    const pattern = new RegExp(`\\b(${config.keywords.join('|')})\\b`, 'i');
    if (pattern.test(textNorm) || pattern.test(cityNorm)) {
         matchedTargets = [...matchedTargets, ...config.targets];
    }
}

// 2. FALLBACK: Global feed (Cualquier ciudad que no coincida con cliente)
if (matchedTargets.length === 0 && (category === 'evento' || category === 'plaza')) {
  matchedTargets.push({ to: "120363425790792660@g.us", label: (cityDetected !== 'global' ? cityDetected.toUpperCase() : 'GLOBAL') });
}

// Ensure unique targets
const uniqueTargets = Array.from(new Set(matchedTargets.map(t => t.to)))
  .map(to => matchedTargets.find(t => t.to === to));

if (uniqueTargets.length === 0) return [];

return uniqueTargets.map(t => ({
  json: { 
    ...leadData, 
    target_wa: t.to, 
    city_label: t.label 
  }
}));

